/**
 * C4 API Client
 */

const API_BASE = process.env.NEXT_PUBLIC_API_URL || 'http://localhost:4000';

export interface Message {
  id: string;
  role: 'user' | 'assistant' | 'system';
  content: string;
  timestamp: string;
  metadata?: Record<string, unknown>;
}

export interface ChatResponse {
  id: string;
  conversation_id: string;
  message: Message;
  done: boolean;
}

export interface Project {
  id: string;
  name: string;
  status: string;
  tasks_done: number;
  tasks_pending: number;
  created_at: string;
}

export interface ProjectDetail extends Project {
  description?: string;
  workers: Record<string, { state: string; task_id: string | null }>;
  recent_events: Array<{ type: string; timestamp: string; data: unknown }>;
}

/**
 * Send a chat message
 */
export async function sendMessage(
  message: string,
  conversationId?: string,
  stream = false
): Promise<ChatResponse> {
  const response = await fetch(`${API_BASE}/api/chat/message`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      message,
      conversation_id: conversationId,
      stream,
    }),
  });

  if (!response.ok) {
    throw new Error(`API error: ${response.status}`);
  }

  return response.json();
}

/**
 * Get conversation history
 */
export async function getHistory(conversationId: string): Promise<Message[]> {
  const response = await fetch(`${API_BASE}/api/chat/history/${conversationId}`);
  
  if (!response.ok) {
    throw new Error(`API error: ${response.status}`);
  }
  
  return response.json();
}

/**
 * Get C4 status
 */
export async function getStatus(): Promise<{
  initialized: boolean;
  status?: string;
  queue?: { pending: number; done: number };
}> {
  const response = await fetch(`${API_BASE}/api/status`);
  
  if (!response.ok) {
    throw new Error(`API error: ${response.status}`);
  }
  
  return response.json();
}

/**
 * Stream chat response using SSE
 */
export function streamMessage(
  message: string,
  conversationId?: string,
  onChunk?: (chunk: string) => void,
  onDone?: (response: ChatResponse) => void,
  onError?: (error: Error) => void
): () => void {
  const controller = new AbortController();
  
  fetch(`${API_BASE}/api/chat/message`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      message,
      conversation_id: conversationId,
      stream: true,
    }),
    signal: controller.signal,
  })
    .then(async (response) => {
      if (!response.ok) {
        throw new Error(`API error: ${response.status}`);
      }
      
      const reader = response.body?.getReader();
      if (!reader) throw new Error('No response body');
      
      const decoder = new TextDecoder();
      let buffer = '';
      
      while (true) {
        const { done, value } = await reader.read();
        if (done) break;
        
        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop() || '';
        
        for (const line of lines) {
          if (line.startsWith('data:')) {
            try {
              const data = JSON.parse(line.slice(5).trim());
              if (data.content && onChunk) {
                onChunk(data.content);
              }
              if (data.done && onDone) {
                onDone(data as ChatResponse);
              }
            } catch {
              // Ignore parse errors
            }
          }
        }
      }
    })
    .catch((error) => {
      if (error.name !== 'AbortError' && onError) {
        onError(error);
      }
    });
  
  return () => controller.abort();
}
